import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"35. Rosters","description":"","frontmatter":{"title":"35. Rosters","eba":"Doctors in Training 2022-2026","topics":["hours","rosters","education-pd","employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/35-rosters.md","filePath":"ebas/doctors-in-training/hours-of-work/35-rosters.md"}'),a={name:"ebas/doctors-in-training/hours-of-work/35-rosters.md"};function n(i,e,h,c,d,l){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_35-rosters" tabindex="-1">35. Rosters <a class="header-anchor" href="#_35-rosters" aria-label="Permalink to &quot;35. Rosters&quot;">​</a></h1><p><strong>35.1</strong> Roster Hours</p><p><strong>(a)</strong> The ordinary hours of work for full-time and part-time Doctors must be worked in accordance with the roster or rosters.</p><p><strong>(b)</strong> Rosters must be prepared taking into account work that should be completed in rostered working hours including theatre preparation, preparation for ward rounds, completing discharge summaries and (for Registrars only) Training Time in accordance with subclause 34.5.</p><p><strong>35.2</strong> Roster Posting</p><p><strong>(a)</strong> A roster of at least 28 days duration that states each Doctor’s daily working hours and start and finishing times must be posted at least 28 days before the roster comes into operation.</p><p><strong>(b)</strong> The roster or rosters must be exhibited at a convenient place accessible to the Doctors to whom it applies.</p><p><strong>35.3</strong> Roster Design – Safe Hours of Work</p><p><strong>(a)</strong> The provisions of this subclause 35.3 are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/hours-of-work/41-workload-management-and-review.html">clause 41</a> (Workload Management and Review).</p><p><strong>(b)</strong> The Health Service must not roster or arrange work hours in a way that causes an excessive or unsafe work pattern to exist and shall apply a framework to consider safe working hours.</p><p><strong>(c)</strong> The obligation to work safe hours applies to both the Health Service and Doctors.</p><p><strong>(d)</strong> The National Code of Practice – Hours of Work, Shiftwork and Rostering for Hospital Doctors in creating rosters is the recommended framework under which to consider safe working hours issues and will be considered by Health Services in meeting their obligations under this clause.</p><p><strong>(e)</strong> At the request of the Ambassador or other authorised representative of the Association, the Health Service will meet to discuss Roster Design – Safe Hours of Work under this clause 35.3</p><p><strong>(f)</strong> It is recognised that unrostered overtime can impact safe hours of work. In addition to raising any concerns about safe hours of work as a result of unrostered overtime with the Employer, Doctors will submit timesheets (or equivalent) with any unrostered overtime within the timeframe required by the Health Service.</p><p><strong>35.4</strong> Roster Requests</p><p><strong>(a)</strong> A Doctor may make a specific request concerning an upcoming roster period. Such request must be made in writing to the Health Service at least one week prior to the date on which the roster must be posted.</p><p><strong>(b)</strong> On receipt of a request made pursuant to subclause 35.4(a) above, the Health Service must consult with the Doctor and other Doctors on the roster to try and accommodate all such requests.</p><p><strong>(c)</strong> The final roster will be determined by the Health Service in consideration of all requests received pursuant to subclause 35.4(a) above. The Health Service must advise the Doctors involved of the reasons for its determination where requests have not been satisfied.</p><p><strong>35.5</strong> Roster Change</p><p><strong>(a)</strong> Rosters will not change without at least fourteen days’ notice of a change in roster other than in an emergency situation external to the Employer or disaster, subject to (b), below</p><p><strong>(b)</strong> If the Health Service requires a Doctor to work ordinary hours outside of the existing roster and has not given fourteen days’ notice of the change and there is no emergency external to the Employer or disaster situation, the Doctor must be paid a daily allowance (Change of Roster Allowance) as follows:</p><p><strong>(i)</strong> 7 days&#39; or less notice, 5 per cent of the Doctor&#39;s ordinary weekly rate of pay for the rostered hours worked per shift; and</p><p><strong>(ii)</strong> 8 to 14 days&#39; notice, 2.5 per cent of the Doctor&#39;s ordinary weekly rate of pay for the rostered hours worked per shift.</p><p><strong>(c)</strong> Where the Doctor is part-time and has agreed to work shift(s) in addition to those rostered, the Doctor is not entitled to the allowance in subclause 35.5(b) above</p><p><strong>(d)</strong> In the circumstances described at (b) (Change of Roster), the Health Service will consult with the Doctor whose roster is being amended to consider the circumstances including the amount of notice, workload impact, the responsibilities of the Doctor (including family responsibilities).</p><p><strong>35.6</strong> For the purposes of this clause 35, an unforeseen medical emergency or disaster situation is not planned leave nor providing a replacement for an unplanned absence.</p><p><strong>35.7</strong> A Doctor may request in writing to alter the roster. The roster may then be altered by agreement with the Health Service.</p><p><strong>35.8</strong> Where Doctors swap rostered shifts, only the penalties and allowances for the shift that the Doctor actually works are payable.</p><p><strong>35.9</strong> Rosters and rotation</p><p>Where a roster (including a change of roster) will include a rotation that has not been previously agreed with the Doctor, the Health Service must seek agreement in accordance with <a href="/eba/ebas/doctors-in-training/doctor-employment/24-rotations-between-hospitals.html">clause 24.3</a> of this Agreement.</p><p><strong>35.10</strong> Notification of a Change of Roster</p><p>Health Services will advise Doctors as to how a change of roster will be notified to affected Doctors</p><p>Plain language terms: rostering, shift roster, duty roster.</p>',33)])])}const u=t(a,[["render",n]]);export{g as __pageData,u as default};
